const Diveder = () => <div className="my-2 border-t-2 border-zinc-400/80 w-32" />;

const Item1 = () => {
  return (
    <div>
      <p className="text-xl md:text-3xl font-calibri-bold">
        <T value="label_private_air" />
      </p>
      <p className="mt-3 font-calibri-regular">
        <T value="label_based_in" />
      </p>
    </div>
  );
};

const Item2 = () => {
  const rows = 17;
  const cols = 11;

  const numbers = [185, 174, 151, 126, 95, 72, 60, 58, 35];
  const names = {
    185: "Cabo San Lucas",
    174: "Todos Santos",
    151: "La Paz",
    126: "Puerto San Carlos",
    95: "Loreto",
    72: "Mulegé",
    60: "Santa Rosalía",
    58: "San Ignacio",
    35: "Guerrero Negro",
  };

  return (
    <div className="relative w-full max-w-[400px] mt-4 xl:mt-0 max-h-[600px]">
      {/* Mapa */}
      <Image alt="" src="/images/img_baja.svg" width={340} height={508} className="w-full h-auto relative z-10" />

      <Image
        alt=""
        src="/images/saltamontes_animation.webp"
        width={672}
        height={356}
        className="w-52 md:w-64 absolute bottom-0 right-1/2 translate-x-1/2"
      />

      {/* Grid overlay */}
      <div
        className="absolute inset-0 grid"
        style={{
          gridTemplateRows: `repeat(${rows}, 1fr)`,
          gridTemplateColumns: `repeat(${cols}, 1fr)`,
        }}
      >
        {Array.from({ length: rows * cols }).map((_, i) => (
          <div key={`item-${i}`} className="flex items-center justify-center relative z-10">
            {numbers.includes(i) && (
              <div className="w-7 h-7 group">
                <div className="w-7 h-7 bg-c_golden rounded-full group-hover:scale-125 transition-all" />
                <div className="absolute -top-10 md:-top-7 -right-8 md:right-3 w-56 bg-c_dark_blue text-white max-w-min text-nowrap rounded-full px-4 py-1 transition-all opacity-0 group-hover:opacity-100 z-10 pointer-events-none ring-2 ring-c_golden">
                  {names[i]}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

const Item3 = () => {
  const lang = localStorage.getItem("lang-avionica") || "en";
  return (
    <div>
      <p className="text-xl font-calibri-bold">
        <T value="label_popular_destinations" />
      </p>

      <Diveder />
      <p className="mt-3 font-calibri-regular">
        <T value="label_popular_destinations_content" />
      </p>
    </div>
  );
};

const Item4 = () => {
  return (
    <div>
      <p className="text-xl font-calibri-bold">
        <T value="label_comfort_modern" />
      </p>
      <Diveder />
      <p className="font-calibri-regular">
        <T value="label_comfort_modern_content" />
      </p>
    </div>
  );
};

const Item5 = () => {
  const lang = localStorage.getItem("lang-avionica") || "en";
  return (
    <div className={cn("col-span-1", lang === "es" && "col-span-2 md:col-span-1")}>
      <p className="text-xl font-calibri-bold">
        <T value="label_local_expertise" />
      </p>
      <Diveder />
      <p className="font-calibri-regular">
        <T value="label_local_expertise_content" />
      </p>
    </div>
  );
};

const Information = () => {
  const lang = localStorage.getItem("lang-avionica") || "en";
  return (
    <section id="about" className="py-10 xl:py-20 overflow-hidden">
      <Container>
        <div className="grid grid-cols-2 xl:grid-cols-4">
          <div className="col-span-2">
            <Item1 />
            <div className="mt-4 xl:mt-10">
              <Item3 />
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4 xl:mt-10">
                <Item4 />
                <Item5 />

                <div className={cn("mt-0 xl:mt-10", lang === "es" ? "col-span-2" : "col-span-1")}>
                  <p className="text-xl font-calibri-bold">
                    <T value="label_unique_experience" />
                  </p>
                  <Diveder />
                  <p className="font-calibri-regular">
                    <T value="label_unique_experience_content" />
                  </p>
                </div>

                {lang === "en" && (
                  <Fragment>
                    <div className="mt-0 xl:mt-10">
                      <p className="text-xl font-calibri-bold">
                        <T value="label_fly_on" />
                      </p>
                      <Diveder />
                      <p className="font-calibri-regular xl:max-w-xs">
                        <T value="label_fly_on_content" />
                      </p>
                    </div>
                  </Fragment>
                )}
              </div>
            </div>
            {/* <div className="grid grid-cols-1 xl:grid-cols-2 gap-4 mt-4 xl:mt-10">
              <div className="col-span-1">
                <Item3 />
              </div>
              <div className="col-span-1">
                <Item4 />
                <Item5 />
              </div>
            </div> */}
          </div>
          <div className="col-span-2 flex justify-end">
            <Item2 />
          </div>
        </div>
      </Container>
    </section>
  );
};

export default Information;
